sql:
SELECT cn0_dbhz
FROM signal_quality
WHERE signal_id = 1;

SELECT satellite_name
FROM satellites
WHERE status = 'active';

SELECT AVG(ionospheric_delay_meters) AS avg_ionospheric_delay
FROM ionospheric_delay
WHERE ionospheric_correction_applied = 1;

SELECT COUNT(*) AS active_satellites_count
FROM satellites
WHERE status = 'active';

SELECT signal_id, message_type, latitude
FROM gnss_signals
WHERE receiver_id = 2 AND message_type = 'Raw';

SELECT AVG(bias_nanos) AS average_bias
FROM gnss_signals
WHERE receiver_id = 1;

SELECT utc_time_millis
FROM gnss_signals
WHERE signal_id = 1;

SELECT AVG(tropospheric_delay_meters) AS average_tropospheric_delay
FROM tropospheric_delay
WHERE signal_id = 1;

external_knowledge:
- 'Strong signals' refers to a signal strength (cn0_dbhz) greater than 40; 
- 'High receiver temperatures' means temperatures greater than 20 degrees Celsius; 
- 'Minimal environmental delays' refers to ionospheric delays less than 10 meters and tropospheric delays less than 5 meters.

